import typing


class ImportFromStringError(Exception):
    pass


def import_from_string(import_str: str) -> typing.Any:
    """
    Import a string like 'module:attribute'
    """
    try:
        module_str, attr_str = import_str.split(":", 1)
    except ValueError:
        raise ImportFromStringError(
            f"Invalid import string '{import_str}'. Must be in format 'module:attribute'"
        )

    try:
        module = __import__(module_str)
    except ImportError as e:
        if e.name == module_str:
            raise ImportFromStringError(f"Module '{module_str}' not found")
        else:
            raise ImportFromStringError(f"Failed to import module '{module_str}': {e}")

    try:
        return getattr(module, attr_str)
    except AttributeError:
        raise ImportFromStringError(
            f"Attribute '{attr_str}' not found in module '{module_str}'"
        )

import typing
from typing import Any, Dict, List, Mapping, Tuple, Type, Union

try:
    from sqlalchemy.engine import ResultProxy
    from sqlalchemy.sql.elements import TextClause
except ImportError:  # pragma: no cover
    pass  # sqlalchemy not installed


class RecordInterface:
    """
    Base interface for record objects.
    """
    pass


class Row:
    """
    A row in a result set that behaves like a tuple and dict.
    """
    def __getitem__(self, key: Any) -> Any:
        """
        An instance of a Row in SQLAlchemy allows the access
        to the Row._fields as tuple and the Row._mapping for
        the values.
        """
        if isinstance(key, int):
            return super().__getitem__(key)

        idx = self._key_to_index[key][0]
        return super().__getitem__(idx)

    def keys(self):
        return self._mapping.keys()

    def values(self):
        return self._mapping.values()


class Record(RecordInterface):
    __slots__ = (
        "_row",
        "_result_columns",
        "_dialect",
        "_column_map",
        "_column_map_int",
        "_column_map_full",
    )

    def __init__(
        self,
        row: Any,
        result_columns: tuple,
        dialect: "Dialect",
        column_maps: Tuple[
            Mapping[Any, Tuple[int, "TypeEngine"]],
            Mapping[int, Tuple[int, "TypeEngine"]],
            Mapping[str, Tuple[int, "TypeEngine"]],
        ],
    ) -> None:
        self._row = row
        self._result_columns = result_columns
        self._dialect = dialect
        self._column_map, self._column_map_int, self._column_map_full = column_maps

    @property
    def _mapping(self) -> Mapping:
        """
        Get the mapping of the record.
        Returns the mapping.
        """
        return self._column_map_full

    def keys(self) -> typing.KeysView:
        """
        Get the keys of the record.
        Returns the keys.
        """
        return self._column_map_full.keys()

    def values(self) -> typing.ValuesView:
        """
        Get the values of the record.
        Returns the values.
        """
        return self._column_map_full.values()

    def __getitem__(self, key: Any) -> Any:
        """
        Get the item from the record.
        Returns the item.
        """
        try:
            if isinstance(key, int):
                index = key
                return self._row[index]
            else:
                index = self._column_map[key][0]
                return self._row[index]
        except (KeyError, IndexError):
            raise KeyError(key)

    def __iter__(self) -> typing.Iterator:
        """
        Iterate over the record.
        Returns an iterator.
        """
        return iter(self._row)

    def __len__(self) -> int:
        """
        Get the length of the record.
        Returns the length.
        """
        return len(self._row)

    def __getattr__(self, name: str) -> Any:
        """
        Get the attribute from the record.
        Returns the attribute.
        """
        try:
            return self[name]
        except KeyError:
            raise AttributeError(f"'{self.__class__.__name__}' object has no attribute '{name}'")


def create_column_maps(result_columns: Any) -> Tuple[
    Mapping[Any, Tuple[int, "TypeEngine"]],
    Mapping[int, Tuple[int, Type["TypeEngine"]]],
    Mapping[str, Tuple[int, Type["TypeEngine"]]]
]:
    """
    Create column maps for a result set.
    """
    column_map: Dict[Any, Tuple[int, "TypeEngine"]] = {}
    column_map_int: Dict[int, Tuple[int, "TypeEngine"]] = {}
    column_map_full: Dict[str, Tuple[int, "TypeEngine"]] = {}

    for i, column in enumerate(result_columns):
        # Column name
        name = column[0] if isinstance(column, tuple) and len(column) > 0 else None
        if name is not None:
            column_map_full[name] = (i, column[1] if isinstance(column, tuple) and len(column) > 1 else None)
            column_map[name] = (i, column[1] if isinstance(column, tuple) and len(column) > 1 else None)

        # Column position
        column_map_int[i] = (i, column[1] if isinstance(column, tuple) and len(column) > 1 else None)

        # Column name with table prefix
        if hasattr(column, 'name'):
            column_name = column.name
            if column_name is not None:
                column_map[column_name] = (i, column[1] if isinstance(column, tuple) and len(column) > 1 else None)

    return (column_map, column_map_int, column_map_full)


